{
  "mode": "method",
  "tests": [
    {
      "name": "createUser_success",
      "input": {
        "username": "testUser",
        "email": "test@example.com",
        "password": "securePassword123"
      },
      "output": {
        "status": "success",
        "message": "User created successfully",
        "userId": "12345"
      },
      "notes": "Validates successful user creation."
    },
    {
      "name": "createUser_duplicateEmail",
      "input": {
        "username": "testUser2",
        "email": "test@example.com",
        "password": "securePassword123"
      },
      "output": {
        "status": "error",
        "message": "Email already in use"
      },
      "notes": "Tests handling of duplicate email addresses."
    },
    {
      "name": "getUser_success",
      "input": "12345",
      "output": {
        "username": "testUser",
        "email": "test@example.com"
      },
      "args": ["12345"],
      "notes": "Validates retrieval of user data by ID."
    },
    {
      "name": "getUser_notFound",
      "input": "99999",
      "output": {
        "status": "error",
        "message": "User not found"
      },
      "args": ["99999"],
      "notes": "Tests retrieval of a non-existent user."
    },
    {
      "name": "downloadReport_success",
      "input": "reportId123",
      "output": {
        "status": "success",
        "message": "Report downloaded successfully",
        "reportData": "base64EncodedReportData"
      },
      "args": ["reportId123"],
      "notes": "Validates successful report download."
    },
    {
      "name": "downloadReport_notFound",
      "input": "reportId999",
      "output": {
        "status": "error",
        "message": "Report not found"
      },
      "args": ["reportId999"],
      "notes": "Tests downloading a non-existent report."
    },
    {
      "name": "requestConsultation_success",
      "input": {
        "userId": "12345",
        "consultationType": "online"
      },
      "output": {
        "status": "success",
        "message": "Consultation requested successfully"
      },
      "notes": "Validates successful consultation request."
    },
    {
      "name": "requestConsultation_invalidType",
      "input": {
        "userId": "12345",
        "consultationType": "invalidType"
      },
      "output": {
        "status": "error",
        "message": "Invalid consultation type"
      },
      "notes": "Tests handling of invalid consultation types."
    }
  ],
  "assumptions": "User IDs and report IDs are unique and valid.",
  "notes": "Ensure all endpoints are tested for both success and error cases."
}
